#!/usr/bin/env bun
/**
 * fetch-bilibili-titles.ts
 * 从B站获取博主"黑鸦"的所有视频标题
 * 支持 WBI 签名
 *
 * 用法:
 *   bun run scripts/fetch-bilibili-titles.ts
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { join } from "node:path";
import { fetchAllVideos } from "./lib/bilibili.ts";

const OUTPUT_DIR = join(import.meta.dir, "../references/research");
const TITLES_PATH = join(OUTPUT_DIR, "01-titles.json");

async function main(): Promise<void> {
  const args = process.argv.slice(2);

  if (args.includes("--help") || args.includes("-h")) {
    console.log("从B站获取博主「黑鸦」的所有视频标题\n");
    console.log("用法:");
    console.log("  bun run scripts/fetch-bilibili-titles.ts");
    process.exit(0);
  }

  let results: Awaited<ReturnType<typeof fetchAllVideos>>;
  try {
    results = await fetchAllVideos();
  } catch (err) {
    console.error(`\n❌ 获取失败: ${(err as Error).message}`);

    // 降级：如果有旧数据就用旧的，避免 pipeline 全崩
    if (existsSync(TITLES_PATH)) {
      const existing = JSON.parse(readFileSync(TITLES_PATH, "utf-8"));
      console.error(
        `⚠️  降级使用缓存数据（${existing.length} 条标题），可能不是最新`,
      );
      results = existing;
    } else {
      console.error("💥 无缓存数据可用，退出");
      process.exit(1);
    }
  }

  mkdirSync(OUTPUT_DIR, { recursive: true });
  writeFileSync(TITLES_PATH, JSON.stringify(results, null, 2), "utf-8");

  console.log("\n✨ 完成！");
  console.log(`  📹 视频总数: ${results.length}`);
  console.log("  💾 数据已保存到 references/research/01-titles.json");
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});

#!/usr/bin/env bun
/**
 * update-skill.ts
 * 读取 02-style-analysis.json + SKILL.example.md 模板，生成 SKILL.md
 *
 * 用法:
 *   bun run scripts/update-skill.ts
 */

import { existsSync, readFileSync, writeFileSync } from "node:fs";
import { join } from "node:path";
import { genCoreFeatures } from "./lib/generate/core-features.ts";
import { genStructureFormulas } from "./lib/generate/structure-formulas.ts";
import { genTitleExamples } from "./lib/generate/title-examples.ts";
import { genVocabLibrary } from "./lib/generate/vocab-library.ts";
import type { AnalysisData } from "./lib/types.ts";

const JSON_PATH = join(
  import.meta.dir,
  "../references/research/02-style-analysis.json",
);
const SKILL_SRC = join(import.meta.dir, "../SKILL.example.md");
const SKILL_OUT = join(import.meta.dir, "../SKILL.md");

/** 加载分析数据 */
function loadAnalysis(): AnalysisData {
  if (!existsSync(JSON_PATH)) {
    console.error("[ERROR] 分析数据不存在，请先运行 analyze-titles.ts");
    process.exit(1);
  }
  return JSON.parse(readFileSync(JSON_PATH, "utf-8")) as AnalysisData;
}

/** 加载 SKILL.example.md 模板 */
function loadSkill(): string {
  if (!existsSync(SKILL_SRC)) {
    console.error("[ERROR] SKILL.example.md 模板不存在");
    process.exit(1);
  }
  return readFileSync(SKILL_SRC, "utf-8");
}

/** 替换 AUTO_START/AUTO_END 标记区域内容 */
function replaceSection(
  content: string,
  sectionName: string,
  newContent: string,
): string {
  const startMarker = `<!-- AUTO_START:${sectionName} -->`;
  const endMarker = `<!-- AUTO_END:${sectionName} -->`;

  const startIdx = content.indexOf(startMarker);
  const endIdx = content.indexOf(endMarker);

  if (startIdx === -1 || endIdx === -1) {
    console.warn(`  ⚠️ 未找到标记 ${sectionName}，跳过`);
    return content;
  }

  const before = content.slice(0, startIdx + startMarker.length);

const startMarker = `<!-- AUTO_START:${sectionName} -->`;
  const endMarker = `<!-- AUTO_END:${sectionName} -->`;

  const startIdx = content.indexOf(startMarker);
  const endIdx = content.indexOf(endMarker);

  if (startIdx === -1 || endIdx === -1) {
    console.warn(`  ⚠️ 未找到标记 ${sectionName}，跳过`);
    return content;
  }

  const before = content.slice(0, startIdx + startMarker.length);
  const after = content.slice(endIdx);
  return `${before}\n${newContent}\n${after}`;
}

function main(): void {
  console.log("📊 加载分析数据...");
  const data = loadAnalysis();
  console.log(`  ✅ 共 ${data.meta.totalVideos} 个视频的分析数据\n`);

  console.log("📝 加载 SKILL.example.md 模板...");
  let skill = loadSkill();

  console.log("🔄 更新数据段落...\n");

  skill = replaceSection(skill, "core-features", genCoreFeatures(data));
  console.log("  ✅ 核心特征");

  skill = replaceSection(skill, "title-examples", genTitleExamples(data));
  console.log("  ✅ 真实标题示例");

  skill = replaceSection(skill, "vocab-library", genVocabLibrary(data));
  console.log("  ✅ 高频词汇库");

  skill = replaceSection(
    skill,
    "structure-formulas",
    genStructureFormulas(data),
  );
  console.log("  ✅ 结构公式与分类占比");

  writeFileSync(SKILL_OUT, skill, "utf-8");
  console.log("\n💾 SKILL.md 已生成（模板 SKILL.example.md 未修改）");
}

main();

import { createHash } from "node:crypto";
import type {
  BilibiliNavResponse,
  BilibiliSearchResponse,
  BilibiliVideoItem,
  VideoEntry,
  WbiKeys,
} from "./types.ts";
import { COOKIE, sleep } from "./utils.ts";

export const UID = "3706929260006322";
const WBI_URL = "https://api.bilibili.com/x/web-interface/nav";
export const SEARCH_URL = "https://api.bilibili.com/x/space/wbi/arc/search";
export const PAGE_SIZE = 50;

// WBI 混淆表
const MIXIN_KEY_ENC_TAB = [
  46, 47, 18, 2, 53, 8, 23, 32, 15, 50, 10, 31, 58, 3, 45, 35, 27, 43, 5, 49,
  33, 9, 42, 19, 29, 28, 14, 39, 12, 38, 41, 13, 37, 48, 7, 16, 24, 55, 40, 61,
  26, 17, 0, 1, 60, 51, 30, 4, 22, 25, 54, 21, 56, 59, 6, 63, 57, 62, 11, 36,
  20, 34, 44, 52,
];

/** 构建请求头 */
export function buildHeaders(): Record<string, string> {
  const headers: Record<string, string> = {
    "User-Agent":
      "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
    Referer: `https://space.bilibili.com/${UID}`,
  };
  if (COOKIE) {
    headers["Cookie"] = COOKIE;
  }
  return headers;
}

/** 获取 WBI 签名密钥 */
export async function getWbiKeys(): Promise<WbiKeys> {
  const resp = await fetch(WBI_URL, { headers: buildHeaders() });
  const json = (await resp.json()) as BilibiliNavResponse;
  const { wbi_img } = json.data;
  return {
    img: wbi_img.img_url.split("/").pop()?.split(".")[0],
    sub: wbi_img.sub_url.split("/").pop()?.split(".")[0],
  };
}

/** 生成 mixin_key */
function getMixinKey(orig: string): string {
  return MIXIN_KEY_ENC_TAB.map((n) => orig[n])
    .join("")
    .slice(0, 32);
}

/** MD5 哈希（用于 WBI 签名） */
function md5(str: string): string {
  return createHash("md5").update(str).digest("hex");
}

/** WBI 签名 */

function getMixinKey(orig: string): string {
  return MIXIN_KEY_ENC_TAB.map((n) => orig[n])
    .join("")
    .slice(0, 32);
}

/** MD5 哈希（用于 WBI 签名） */
function md5(str: string): string {
  return createHash("md5").update(str).digest("hex");
}

/** WBI 签名 */
export function encWbi(
  params: Record<string, string | number | boolean>,
  imgKey: string,
  subKey: string,
): string {
  const mixinKey = getMixinKey(imgKey + subKey);
  const wts = Math.round(Date.now() / 1000);
  const signedParams = { ...params, wts };

  const query = Object.keys(signedParams)
    .sort()
    .map((key) => `${key}=${encodeURIComponent(String(signedParams[key]))}`)
    .join("&");

  const wbiSign = md5(query + mixinKey);
  return `${query}&w_rid=${wbiSign}`;
}

/** 重试 + 指数退避 */
export async function withRetry<T>(
  fn: () => Promise<T>,
  label: string,
  maxRetries = 3,
): Promise<T> {
  let lastErr: Error | undefined;
  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (err) {
      lastErr = err as Error;
      if (i < maxRetries - 1) {
        const wait = Math.min(1000 * 2 ** i, 8000);
        console.error(
          `  ⚠️ ${label} 失败 (${i + 1}/${maxRetries})，${wait / 1000}s 后重试...`,
        );
        await sleep(wait);
      }
    }
  }
  throw new Error(`${label}: ${lastErr?.message}`);
}

