/** 生成「核心特征」段落 */
export function genCoreFeatures(data: AnalysisData): string {
  const { length, punctuation, aiDaily, patterns, keywords } = data;
  const lines: string[] = [];
  lines.push("### 核心特征");
  lines.push("");
  lines.push(
    `1. **超长标题**：平均 ${length.avg} 字，${length.over40Pct}% 超过 40 字`,
  );
  lines.push(
    `2. **情绪炸弹**：大量使用感叹号（${Math.round(punctuation.exclamationEnd * 100)}%）和情绪词`,
  );
  lines.push("3. **多事件合并**：一个标题常包含 2-3 条新闻");

  const dominant = Object.entries(patterns.structure)
    .filter(([cat]) => cat !== "其他")
    .sort((a, b) => b[1].count - a[1].count)[0];
  if (dominant) {
    lines.push(
      `4. **AI 日报格式**：${aiDaily.pct}% 的标题带 "| AI日报MMDD" 后缀`,
    );
    lines.push(
      `5. **主导风格**：「${dominant[0]}」占比 ${dominant[1].pctDisplay}`,
    );
  }
  lines.push(
    `6. **独特词汇**：${keywords.uniqueExpressions.slice(0, 10).join("、")}`,
  );
  lines.push("");

  return lines.join("\n");
}

import type { AnalysisData } from "../types.ts";

/** 生成「结构公式」段落 */
export function genStructureFormulas(data: AnalysisData): string {
  const structure = data.patterns.structure;
  const lines: string[] = [];

  // 公式1: 情感式
  if (
    structure["情感式"]?.templates?.length &&
    structure["情感式"].templates.length > 0
  ) {
    lines.push(
      `**公式1：情绪词 + 主题 + 副标题（最常用，${structure["情感式"].pctDisplay}）**`,
    );
    lines.push("```");
    lines.push("{情绪词}！{主题}，{副标题}！");
    lines.push("```");
    lines.push("");
  }

  // 公式2: 多事件合并
  lines.push("**公式2：多事件合并**");
  lines.push("```");
  lines.push("{事件1}！{事件2}！{事件3}！| AI日报{MMDD}");
  lines.push("```");
  lines.push("");

  // 公式3: 悬念式
  if (
    structure["悬念式"]?.templates?.length &&
    structure["悬念式"].templates.length > 0
  ) {
    lines.push(`**公式3：悬念式（${structure["悬念式"].pctDisplay}）**`);
    lines.push("```");
    lines.push("{情绪词}！{主题}泄露/曝出/传出，{副标题}？");
    lines.push("```");
    lines.push("");
  }

  // 公式4: 日报式
  lines.push(`**公式4：日报式（${data.aiDaily.pct}%）**`);
  lines.push("```");
  lines.push("{主题} | AI日报{MMDD}");
  lines.push("```");
  lines.push("");

  // 分类占比表
  lines.push("### 分类占比");
  lines.push("");
  lines.push("| 类型 | 数量 | 占比 |");
  lines.push("|------|------|------|");
  for (const [cat, info] of Object.entries(structure)) {
    lines.push(`| ${cat} | ${info.count} | ${info.pctDisplay} |`);
  }
  lines.push("");

  return lines.join("\n");
}

