  );
  lines.push("");

  lines.push("**AI 领域词**：");
  lines.push(
    aiTerms
      .slice(0, 15)
      .map((e) => e.word)
      .join("、"),
  );
  lines.push("");

  lines.push("**高频词 Top 20**：");
  lines.push(
    highFrequency
      .slice(0, 20)
      .map((e) => `${e.word}(${e.count})`)
      .join("、"),
  );
  lines.push("");

  return lines.join("\n");
}

